# agent/tools.py — integrating the guard into tool dispatch
from agent.tool_guard import check_tool, ToolDisabledError

def dispatch_tool(tool_name: str, tool_input: dict) -> dict:
    """
    Dispatch a tool call from the agent loop.
    Checks the kill switch before execution.
    """
    try:
        check_tool(tool_name)
    except ToolDisabledError as exc:
        # Return a structured error that the agent can reason about
        return {
            "type":    "tool_error",
            "tool":    tool_name,
            "message": str(exc),
        }

    # Route to the actual tool implementation
    tool_fn = _TOOL_REGISTRY.get(tool_name)
    if tool_fn is None:
        return {"type": "tool_error", "tool": tool_name, "message": "unknown tool"}
    return tool_fn(tool_input)

_TOOL_REGISTRY = {
    "write_to_database": _write_to_database,
    "send_email":        _send_email,
    "call_payment_api":  _call_payment_api,
}

# app/handlers/summary.py — agent handler with kill switch check
import anthropic
from agent.kill_switch import agent_is_enabled

_client = anthropic.Anthropic()
_STATIC_FALLBACK = {
    "summary":   None,
    "error":     "Summary service is temporarily unavailable. Please try again later.",
    "fallback":  True,
}

def handle_summary_request(user_id: str, document_text: str) -> dict:
    if not agent_is_enabled("summary-agent"):
        return _STATIC_FALLBACK

    response = _client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        messages=[{
            "role":    "user",
            "content": f"Summarise the following in 3 bullet points:\n\n{document_text}",
        }],
    )
    return {"summary": response.content[0].text, "fallback": False}
